from flask import Flask, request

app = Flask(__name__)

@app.route('/welcome')
def welcome():
    name = request.args.get('name', 'Guest')
    return f"<html><body><h1>Welcome, <strong>{name}</strong></h1><p>We are glad to have you here!</p></body></html>"

if __name__ == '__main__':
    app.run(debug=True)